    const saved = localStorage.getItem('app-theme') as Theme;
    if (saved) return saved;
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  });
  const [isInitialLoading, setIsInitialLoading] = useState(true);
